-- Name: fn_get_admitcard(character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_get_admitcard(_table_name1 character varying, _table_name2 character varying, _dob character varying, _tier_id character varying, _reg_no character varying) RETURNS json
    LANGUAGE plpgsql
    AS $$

Declare

		json_data json;

	BEGIN

	--  SET search_path to nursecounsil;

	 json_data:=(select  array_to_json(array_agg(row_to_json(t)))from (

	select  kd.*,ted.*,t.tier_name, t.tier_id , CONCAT(kd.present_address,', ',kd.present_district,', ',kd.present_state,', ',kd.present_pincode) as candidate_address  from _table_name1 kd

     JOIN _table_name2 ted ON kd.reg_no = ted.reg_no and kd.exam_code = ted.exam_code 
     JOIN tier_master t ON ted.tier_id = cast(t.tier_id as char(255))
    where kd.dob=_dob and kd.reg_no=_reg_no and ted.tier_id=_tier_id

	 ) t) ;

		   return json_data;

	 End;

$$;


ALTER FUNCTION public.fn_get_admitcard(_table_name1 character varying, _table_name2 character varying, _dob character varying, _tier_id character varying, _reg_no character varying) OWNER TO postgres;

